const blank = v => !v || v.trim() === '' || v.trim().toLowerCase() === 'empty';

let email = {};
try { email = $('Gmail Trigger').first().json; } catch(e) {}

return $input.all().map(item => {
  const response = item.json.text || '';

  let data = {
    hasAppointment: false,
    title: '',
    date: '',
    startTime: '',
    endTime: '',
    description: '',
    location: '',
    hasTodo: false,
    todoTitle: '',
    todoSubItems: [],
    emailFrom: email.from || '',
    emailDate: email.date || '',
    emailSubject: email.subject || ''
  };

  try {
    const match = response.match(/\{[\s\S]*\}/);
    if (match) data = { ...data, ...JSON.parse(match[0]) };
  } catch (e) {}

  // --- Appointment normalization ---
  if (data.hasAppointment && blank(data.date)) data.hasAppointment = false;
  if (blank(data.location))    data.location    = '';
  if (blank(data.description)) data.description = '';
  if (blank(data.startTime))   data.startTime   = '09:00';
  if (blank(data.endTime)) {
    const [h, m] = data.startTime.split(':').map(Number);
    data.endTime = String(h + 1).padStart(2, '0') + ':' + String(m).padStart(2, '0');
  }

  // Fix year: if missing, wrong, or in the past — use current/next year
  if (data.hasAppointment && data.date && /^\d{4}-\d{2}-\d{2}$/.test(data.date)) {
    const now = new Date();
    const curYear = now.getFullYear();
    const [y, mo, d] = data.date.split('-').map(Number);
    if (y < curYear || y > curYear + 2) {
      const candidate = new Date(curYear, mo - 1, d);
      const useYear = candidate < now ? curYear + 1 : curYear;
      data.date = `${useYear}-${String(mo).padStart(2,'0')}-${String(d).padStart(2,'0')}`;
    }
  }

  // --- Todo normalization ---
  if (!Array.isArray(data.todoSubItems)) data.todoSubItems = [];

  // Appointment → always force a todo with a structured, date-guaranteed title
  if (data.hasAppointment) {
    data.hasTodo = true;
    const [y, mo, d] = (data.date || '').split('-');
    const dateStr = data.date ? `${d}.${mo}.${y}` : '';
    const timeStr = data.startTime ? ` um ${data.startTime} Uhr` : '';
    data.todoTitle = `📅 Termin: ${data.title || email.subject || 'Unbekannt'}${dateStr ? ' – ' + dateStr + timeStr : ''}`;
  }

  // Fallback title for non-appointment todos
  if (data.hasTodo && blank(data.todoTitle)) {
    data.todoTitle = email.subject || 'Follow-up';
  }

  // Disable todo if still no title
  if (data.hasTodo && blank(data.todoTitle)) data.hasTodo = false;

  // ALWAYS append [empfangen: DD.MM.YYYY HH:MM] — guaranteed format
  if (data.hasTodo) {
    let ts = '';
    try {
      const dt = new Date(email.date || Date.now());
      const fmt = new Intl.DateTimeFormat('de-DE', {
        timeZone: 'Europe/Berlin',
        day: '2-digit', month: '2-digit', year: 'numeric',
        hour: '2-digit', minute: '2-digit', hour12: false
      });
      const p = fmt.formatToParts(dt);
      const g = t => p.find(x => x.type === t)?.value || '00';
      ts = `${g('day')}.${g('month')}.${g('year')} ${g('hour')}:${g('minute')}`;
    } catch(e) {
      ts = new Date().toLocaleDateString('de-DE');
    }
    data.todoTitle += ` [empfangen: ${ts}]`;
  }

  return { json: data };
});
